        if not refresh_token:
            raise InvalidGrantError("Invalid refresh token")

        if refresh_token.revoked:
            logger.warning(
                "SECURITY: Revoked refresh token used by client %s",
                client.client_id,
            )
            raise InvalidGrantError("Refresh token has been revoked")

